"use client";

import React from "react";
import { Card, Button, Badge } from "@/components/marketing/ui";
import {
  certificateId,
  getExam,
  type SkillBand,
} from "@/lib/marketing-tests/exams";

export interface ExamResult {
  attemptId: string;
  examId: string;
  examTitle: string;
  domain: string;
  score: number;
  total: number;
  correctCount: number;
  percentage: number;
  passed: boolean;
  band: SkillBand;
  skillBreakdown: Record<string, { correct: number; total: number; pct: number }>;
  answers: unknown[];
  candidate: string;
  email: string;
  elapsedSeconds: number;
  timedOut: boolean;
  tabSwitches: number;
  takenAt: number;
}

function formatDuration(totalSeconds: number): string {
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  return `${minutes}m ${seconds.toString().padStart(2, "0")}s`;
}

function formatLocalDate(epochMs: number): string {
  return new Date(epochMs).toLocaleDateString(undefined, {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

export function ExamCertificate({ result }: { result: ExamResult }) {
  if (!result.passed) {
    return (
      <Card className="border-2 border-gray-200 bg-gray-50 p-8 text-center">
        <div className="mx-auto flex max-w-md flex-col items-center gap-4">
          <div className="flex h-16 w-16 items-center justify-center rounded-full bg-gray-100 text-3xl">
            📋
          </div>
          <h2 className="text-xl font-bold text-gray-900">
            Certificate not earned
          </h2>
          <p className="text-sm text-gray-500">
            You did not reach the passing threshold for the{" "}
            <span className="font-semibold text-gray-700">
              {result.examTitle}
            </span>{" "}
            assessment. Review your skill breakdown and retake the exam to earn
            your certification.
          </p>
          <div className="mt-2 flex items-center gap-3 text-sm">
            <Badge variant="outline" className="border-gray-300 text-gray-600">
              Score: {result.correctCount}/{result.total}
            </Badge>
            <Badge
              variant="destructive"
              className="bg-red-100 text-red-700"
            >
              {result.percentage}%
            </Badge>
          </div>
          <Button
            variant="outline"
            className="mt-2 border-gray-300 text-gray-700"
            onClick={() => undefined}
          >
            Review results
          </Button>
        </div>
      </Card>
    );
  }

  const exam = getExam(result.examId);
  const level = exam?.level;
  const certId = certificateId(result.examId, result.candidate, result.takenAt);
  const issuedDate = formatLocalDate(result.takenAt);
  const duration = formatDuration(result.elapsedSeconds);

  return (
    <Card className="mx-auto max-w-3xl border-4 border-indigo-200 bg-white p-8 print:border-gray-300">
      <div className="flex flex-col items-center gap-8">
        {/* Header / wordmark + seal */}
        <div className="flex w-full items-center justify-between border-b border-gray-200 pb-6">
          <div className="flex flex-col">
            <span className="text-xs font-semibold uppercase tracking-[0.2em] text-indigo-600">
              Marketing Hub
            </span>
            <span className="text-sm font-medium uppercase tracking-wide text-gray-500">
              Certification Authority
            </span>
          </div>
          <div className="flex flex-col items-center gap-1">
            <div className="flex h-20 w-20 items-center justify-center rounded-full border-4 border-amber-300 bg-amber-50 text-4xl shadow-sm">
              🏅
            </div>
            <span className="text-[10px] font-semibold uppercase tracking-wider text-amber-700">
              Certified Marketing Professional
            </span>
          </div>
        </div>

        {/* Statement */}
        <div className="text-center">
          <p className="text-base leading-relaxed text-gray-700">
            This is to certify that{" "}
            <span className="font-bold text-gray-900">{result.candidate}</span>{" "}
            has successfully completed the{" "}
            <span className="font-bold text-gray-900">
              {result.examTitle}
            </span>{" "}
            assessment with a grade of{" "}
            <span className="font-bold text-indigo-600">
              {result.band.band} ({result.percentage}%)
            </span>
            .
          </p>
        </div>

        {/* Metadata grid */}
        <div className="grid w-full grid-cols-2 gap-4 border-y border-gray-200 py-6 sm:grid-cols-3">
          <MetaItem label="Domain" value={result.domain} />
          <MetaItem
            label="Level"
            value={level ? level : "—"}
          />
          <MetaItem
            label="Score"
            value={`${result.correctCount}/${result.total}`}
          />
          <MetaItem label="Duration" value={duration} />
          <MetaItem label="Date" value={issuedDate} />
          <MetaItem
            label="Tab switches"
            value={`Integrity verified — ${result.tabSwitches} tab switches logged`}
            muted
          />
        </div>

        {/* Certificate ID */}
        <div className="flex w-full flex-col items-center gap-2">
          <span className="text-xs font-semibold uppercase tracking-wider text-gray-500">
            Certificate ID
          </span>
          <div className="rounded-md border border-gray-300 bg-gray-50 px-6 py-3 font-mono text-lg font-semibold text-gray-900">
            {certId}
          </div>
          <span className="text-xs text-gray-500">
            Verify at your recruiting portal
          </span>
        </div>

        {/* Skill summary */}
        <div className="w-full">
          <h3 className="mb-3 text-center text-xs font-semibold uppercase tracking-wider text-gray-500">
            Skill Breakdown
          </h3>
          <div className="overflow-hidden rounded-lg border border-gray-200">
            <table className="w-full text-sm">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-2 text-left text-xs font-semibold uppercase tracking-wide text-gray-500">
                    Skill
                  </th>
                  <th className="px-4 py-2 text-right text-xs font-semibold uppercase tracking-wide text-gray-500">
                    Correct
                  </th>
                  <th className="px-4 py-2 text-right text-xs font-semibold uppercase tracking-wide text-gray-500">
                    Score
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {Object.entries(result.skillBreakdown).map(([skill, stats]) => (
                  <tr key={skill} className="bg-white">
                    <td className="px-4 py-2 font-medium text-gray-900">
                      {skill}
                    </td>
                    <td className="px-4 py-2 text-right text-gray-600">
                      {stats.correct}/{stats.total}
                    </td>
                    <td className="px-4 py-2 text-right">
                      <Badge
                        variant="secondary"
                        className={
                          stats.pct >= 80
                            ? "bg-green-100 text-green-700"
                            : stats.pct >= 60
                              ? "bg-amber-100 text-amber-700"
                              : "bg-gray-100 text-gray-700"
                        }
                      >
                        {stats.pct}%
                      </Badge>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Footer */}
        <div className="w-full border-t border-gray-200 pt-4 text-center">
          <p className="text-xs text-gray-500">
            Issued {issuedDate} · Marketing Hub Recruiting Authority · Void if
            altered
          </p>
        </div>
      </div>
    </Card>
  );
}

function MetaItem({
  label,
  value,
  muted,
}: {
  label: string;
  value: string;
  muted?: boolean;
}) {
  return (
    <div className="flex flex-col gap-1">
      <span className="text-[10px] font-semibold uppercase tracking-wider text-gray-400">
        {label}
      </span>
      <span
        className={
          muted
            ? "text-xs text-gray-500"
            : "text-sm font-medium text-gray-900"
        }
      >
        {value}
      </span>
    </div>
  );
}

